--- 爱欲小径 格子
local LxNodeBase = require("LApp.component.LxNodeBase")
---@class LDesireTrailGridObj:LxNodeBase
local LDesireTrailGridObj = LxClass("LDesireTrailGridObj", LxNodeBase)

local CS = CS
local Tweening = DG.Tweening

local GridStatus = ModelDesireTrail.GridStatus

function LDesireTrailGridObj:Create(map, obj, parnet, y, x)
    self._map = map
    self._obj = obj
    self._y = y
    self._x = x
    self._transform = obj.transform
    self._transform:SetParent(parnet, false)
    obj:SetActive(true)

    obj.name = y .. "_" .. x
    self._model = gModelDesireTrail

    self:InitUI()
    self:Refresh()
end

-- 初始化ui
function LDesireTrailGridObj:InitUI()
    local transform = self._transform
    self._bg = CS.FindTrans(transform, "Bg")
    self._boxEff = CS.FindTrans(transform, "BoxEff")
    self._doorEff = CS.FindTrans(transform, "Door")
    self._icon = CS.FindTrans(transform, "Icon")
    self._spine = CS.FindTrans(transform, "Spine")
    self._title = CS.FindTrans(transform, "ImgTitle/Title")
    self._imgTitle = CS.FindTrans(transform, "ImgTitle")

    local comp = CS.BuildingClick.Get(transform.gameObject)
    comp.ClickDelegate = function() self:OnClickGrid() end

    local comp = CS.BuildingClick.Get(self._imgTitle.gameObject)
    comp.ClickDelegate = function() self:OnClickTitle() end

    local name = gModelDesireTrail:GetCurThemeGridUpOrDownAnim()
    local eff = LDisplayEffect:New()
    eff:CreateEffect(self._bg, name)
    eff:SetResTag(CS.RES_TAG_SCENE)
    self._bgEffObj = eff
    eff:StartLoadEffect()
    CS.ShowObject(self._imgTitle, false)
    self:SetXTextMeshProContent(self._title, ccClientText(45440), nil)
end

-- 设置位置
function LDesireTrailGridObj:SetPos(pos)
    self._transform.localPosition = pos
end

-- 获取位置
function LDesireTrailGridObj:GetPos()
    return self._transform.localPosition
end

-- 获取格子位置
function LDesireTrailGridObj:GetGridPos()
    return self._y, self._x
end

-- true: 表示同一格子
function LDesireTrailGridObj:IsSameGrid(y, x)
    return self._y == y and self._x == x
end

-- 刷新格子
function LDesireTrailGridObj:Refresh()
    local model = self._model
    local data = model:GetGridData(self._y, self._x)
    if not data then return end

    local status = data.status
    local ref = gModelDesireTrail:GetEventConfig(data.refId)
    if not ref then
        if status == GridStatus.HasMove then
            if model:IsLastGrid(self._y, self._x) then
                if model:IsMaxTheme() then
                    self:ShowBoxEffect(true)
                else
                    self:ShowDoor(true)
                end
            end
        end
        return
    end

    local showTitle = false
    local scale = Vector3(ref.resSize, ref.resSize, ref.resSize)


    if ref.resType == 1 then
        -- 图片
        self:SetSpriteRenderer(self._icon, ref.res)
        self._icon.localScale = scale
    elseif ref.resType == 2 then
        -- 精灵
        local dp = LDisplaySpine:New()
        dp:CreateSpine(self._spine, ref.prefab)
        self._dpObj = dp
        dp:SetLoadedFunction(function()
            if self:IsDestroy() then return end

            local trans = dp:GetDisplayTrans()
            trans.localScale = scale
            dp:SetRenderOrder(100)
        end)
        dp:StartLoad()
    elseif ref.resType == 3 then
        -- 特效
    end

    CS.ShowObject(self._imgTitle, showTitle)
    if status == GridStatus.Disappear and not model:NeedPlayAnim(self._y, self._x) then
        if self._obj then
            self._obj:SetActive(false)
        end
    end
    self:CheckBoxStatus()
end

-- 检查宝箱状态
function LDesireTrailGridObj:CheckBoxStatus()
    local data = self._model:GetGridData(self._y, self._x)
    if not data then return end


    local ref = gModelDesireTrail:GetEventConfig(data.refId)
    if ref.type ~= 3 then return end

    local status = data.status
    -- 宝箱
    if status == GridStatus.CanMove or status == GridStatus.Selected then
        self:ShowBoxEffect(false)
    elseif status == GridStatus.HasMove then
        self:ShowBoxEffect(true)
    end
end

-- 显示标题
function LDesireTrailGridObj:ShowTitle()
    CS.ShowObject(self._imgTitle, true)
end

-- 显示空白
function LDesireTrailGridObj:ShowEmpty(bShow)
    bShow = bShow or false and true

    CS.ShowObject(self._icon, bShow)
    CS.ShowObject(self._spine, bShow)
    CS.ShowObject(self._imgTitle, bShow)
end

-- 点击格子
function LDesireTrailGridObj:OnClickGrid()
    self._map:OnClickGrid(self._y, self._x)
end

-- 点击标题
function LDesireTrailGridObj:OnClickTitle()
    self._map:OnClickTitle(self._y, self._x)
end

-- 消失
function LDesireTrailGridObj:FadeOut(time, endFunc)
    time = time or 1
    local _, name = gModelDesireTrail:GetCurThemeGridUpOrDownAnim()
    local eff = LDisplayEffect:New()
    eff:CreateEffect(self._bg, name)
    eff:SetResTag(CS.RES_TAG_SCENE)
    eff:SetLoadedFunction(function(eff)
        if self._bgEffObj then
            self._bgEffObj:Destroy()
            self._bgEffObj = nil
        end
        self._bgEffObj = eff

        if self._spine then
            local tw = self._spine:DOScale(0, time)
            tw:Play()
            tw:OnComplete(function()
                if self._obj then
                    self._obj:SetActive(false)
                end
                if endFunc then
                    endFunc()
                end
            end)
        end
    end)

    eff:StartLoadEffect()
end

-- 显示宝箱特效
function LDesireTrailGridObj:ShowBoxEffect(isOpen, effName)
    if not effName then
        effName = isOpen and "fx_ui_aiyu_baoxiang_hit" or "fx_ui_aiyu_baoxiang_idle"
    end

    CS.ShowObject(self._icon, false)

    if self._boxEffObj then
        self._boxEffObj:Destroy()
        self._boxEffObj = nil
    end

    local eff = LDisplayEffect:New()
    self._boxEffObj = eff
    eff:CreateEffect(self._boxEff, effName)
    eff:SetResTag(CS.RES_TAG_SCENE)
    eff:SetLoadedFunction(function()
        if not self._boxEffObj then return end

        local trans = self._boxEffObj:GetDisplayTrans()
        trans.localScale = Vector3(0.7, 0.7, 0.7)
    end)

    eff:StartLoadEffect()
end

-- 显示传送门
function LDesireTrailGridObj:ShowDoor(enter, time, endFunc)
    CS.ShowObject(self._spine, false)
    CS.ShowObject(self._icon, false)

    if self._boxEffObj then
        self._boxEffObj:Destroy()
        self._boxEffObj = nil
    end

    if self._doorEffObj then
        self._doorEffObj:Destroy()
        self._doorEffObj = nil
    end

    local effName = enter and "fx_ui_aiyu_chuansongmen_1" or "fx_ui_aiyu_chuansongmen_2"

    local eff = LDisplayEffect:New()
    self._doorEffObj = eff
    eff:CreateEffect(self._doorEff, effName)
    eff:SetResTag(CS.RES_TAG_SCENE)

    eff:SetLoadedFunction(function()
        if not self._doorEffObj then return end

        local trans = self._doorEffObj:GetDisplayTrans()
        trans.localPosition = Vector3(0, 0.65, 0)
        trans.localScale = Vector3(0.7, 0.7, 0.7)
    end)
    eff:StartLoadEffect()
    time = time or 1
    local tw = self._doorEff:DOScale(1, 1)
    tw:Play()
    tw:OnComplete(function()
        if endFunc then
            endFunc()
        end
    end)
end

-- true: 已销毁
function LDesireTrailGridObj:IsDestroy()
    return self._isDestroy == true
end

-- 销毁
function LDesireTrailGridObj:Destroy()
    self._isDestroy = true

    if self._dpObj then
        self._dpObj:Destroy()
        self._dpObj = nil
    end

    if self._bgEffObj then
        self._bgEffObj:Destroy()
        self._bgEffObj = nil
    end

    if self._boxEffObj then
        self._boxEffObj:Destroy()
        self._boxEffObj = nil
    end

    if self._doorEffObj then
        self._doorEffObj:Destroy()
        self._doorEffObj = nil
    end

    LxUnity.GameObject.Destroy(self._obj)
    self._obj = nil
    LxNodeBase.Dispose(self)
end

return LDesireTrailGridObj
